args.query:
SELECT "Patient_description" AS participant_barcode, "histological_type", "vital_status" 
FROM clinical_info
WHERE "cancer_type_acronym" = 'BRCA' AND "vital_status" = 'Alive' AND "Patient_description" IS NOT NULL AND "histological_type" IS NOT NULL;

